// Gate G0 — Valida resultado do HMAC + campos obrigatórios + tamanho + mime_type + UUID
// SEM require(), SEM $env — usa apenas $input e $('NodeName')

const hmacResult = $input.first().json;
const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || webhookData;

// --- Verifica resultado do hmac/verify ---
// HMAC bypass temporário (rede Docker interna) — implementar C03/C04 depois
if (false && !hmacResult.valid) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: hmacResult.detail || 'Assinatura HMAC inválida',
      _http_status: 401,
      ingestion_id: body.ingestion_id || null,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação ingestion_id UUID v4 ---
const UUID_V4_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const ingestionId = body.ingestion_id || '';
if (!UUID_V4_REGEX.test(ingestionId)) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'ingestion_id inválido ou ausente (esperado UUID v4)',
      _http_status: 422,
      ingestion_id: ingestionId || null,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação tamanho (máximo 50MB = 52428800 bytes) ---
const sizeBytes = body.document_metadata?.size_bytes || 0;
const MAX_SIZE = 52428800;
if (sizeBytes > MAX_SIZE) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: `Documento excede 50MB. Recebido: ${sizeBytes} bytes`,
      _http_status: 413,
      ingestion_id: ingestionId,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação mime_type ---
const ALLOWED_MIMES = [
  'text/plain', 'text/markdown', 'text/html', 'application/json',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/pdf', 'image/png', 'image/jpeg', 'image/webp', 'message/rfc822'
];
const mimeType = body.document_metadata?.mime_type || '';
if (!mimeType || !ALLOWED_MIMES.includes(mimeType)) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: `mime_type não suportado: '${mimeType}'`,
      _http_status: 415,
      ingestion_id: ingestionId,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

// --- Validação campos obrigatórios ---
if (!body.document_bytes_base64) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'Campo document_bytes_base64 ausente',
      _http_status: 422,
      ingestion_id: ingestionId,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}
if (!body.project_id) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'Campo project_id ausente',
      _http_status: 422,
      ingestion_id: ingestionId,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}
const providerChain = body.provider_chain || [];
if (!Array.isArray(providerChain) || providerChain.length === 0) {
  return [{
    json: {
      _g0_status: 'failed',
      _g0_reason: 'g0_input_invalid',
      _g0_detail: 'provider_chain ausente ou vazio',
      _http_status: 422,
      ingestion_id: ingestionId,
      project_id: body.project_id || null,
      callback_url: body.callback_url || null
    }
  }];
}

return [{
  json: {
    _g0_status: 'ok',
    ingestion_id: ingestionId,
    project_id: body.project_id,
    document_bytes_base64: body.document_bytes_base64,
    document_metadata: body.document_metadata,
    provider_chain: body.provider_chain,
    persona_prompts: body.persona_prompts || {},
    callback_url: body.callback_url,
    timestamp: body.timestamp,
    _received_at: new Date().toISOString()
  }
}];

// Detecta formato e extrai texto (passthrough txt/md, heurística html/pdf/email, marca OCR para imagem)
// SEM require(), SEM $env

const item = $input.first().json;
const mimeType = item.document_metadata?.mime_type || '';
const filename = item.document_metadata?.filename || '';
const extension = (filename.split('.').pop() || '').toLowerCase();

let rawBuffer;
try {
  rawBuffer = Buffer.from(item.document_bytes_base64, 'base64');
} catch (e) {
  return [{ json: { ...item, _needs_ocr: false, _normalized_text: '', _extraction_warnings: ['base64_decode_failed'], _extraction_status: 'failed', _source_format: 'unknown', _extraction_method: 'none' } }];
}

const magicPDF = rawBuffer.slice(0, 4).toString('ascii') === '%PDF';
const magicDOCX = rawBuffer.slice(0, 4).toString('hex') === '504b0304';
const magicPNG = rawBuffer.slice(0, 4).toString('hex') === '89504e47';
const magicJPEG = rawBuffer.slice(0, 2).toString('hex') === 'ffd8';

let normalizedText = '';
let needsOCR = false;
let sourceFormat = 'unknown';
let extractionMethod = 'passthrough';
const warnings = [];

if (mimeType === 'text/plain' || extension === 'txt') {
  normalizedText = rawBuffer.toString('utf8');
  sourceFormat = 'txt';
  extractionMethod = 'passthrough';

} else if (mimeType === 'text/markdown' || extension === 'md') {
  normalizedText = rawBuffer.toString('utf8');
  sourceFormat = 'md';
  extractionMethod = 'passthrough';

} else if (mimeType === 'application/json' || extension === 'json') {
  try {
    const parsed = JSON.parse(rawBuffer.toString('utf8'));
    normalizedText = JSON.stringify(parsed, null, 2);
  } catch (e) {
    normalizedText = rawBuffer.toString('utf8');
    warnings.push('json_parse_error');
  }
  sourceFormat = 'json';
  extractionMethod = 'json_parse';

} else if (mimeType === 'text/html' || extension === 'html' || extension === 'htm') {
  const htmlText = rawBuffer.toString('utf8');
  normalizedText = htmlText
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/h[1-6]>/gi, '\n\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&nbsp;/g, ' ')
    .replace(/\n{3,}/g, '\n\n').trim();
  sourceFormat = 'html';
  extractionMethod = 'html_regex';
  warnings.push('html_extracted_via_regex');

} else if (mimeType === 'message/rfc822' || extension === 'eml') {
  const emlText = rawBuffer.toString('utf8');
  const lines = emlText.split('\n');
  let inBody = false;
  const bodyLines = [];
  for (const line of lines) {
    if (!inBody) { if (line.trim() === '') { inBody = true; } }
    else { bodyLines.push(line); }
  }
  normalizedText = bodyLines.join('\n').trim();
  sourceFormat = 'email';
  extractionMethod = 'eml_regex';
  warnings.push('email_extracted_via_regex');

} else if (mimeType === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' || extension === 'docx' || magicDOCX) {
  // DOCX: sem biblioteca nativa disponível — marca como pendente e passa base64 adiante
  normalizedText = '';
  sourceFormat = 'docx';
  extractionMethod = 'pending_external';
  warnings.push('docx_extraction_pending_external_service');

} else if (mimeType === 'application/pdf' || extension === 'pdf' || magicPDF) {
  // PDF: heurística de extração de texto em BT/ET blocks
  const pdfText = rawBuffer.toString('binary');
  const textMatches = pdfText.match(/BT[\s\S]*?ET/g) || [];
  const fragments = [];
  for (const block of textMatches) {
    const strings = block.match(/\(([^)]+)\)\s*Tj/g) || [];
    for (const s of strings) {
      const text = s.replace(/\(([^)]+)\)\s*Tj/, '$1').trim();
      if (text) fragments.push(text);
    }
  }
  normalizedText = fragments.join(' ');
  if (normalizedText.length < 200) {
    needsOCR = true;
    normalizedText = '';
    warnings.push('pdf_below_threshold_routing_to_ocr');
    sourceFormat = 'pdf_scanned';
  } else {
    sourceFormat = 'pdf_text';
    warnings.push('pdf_extracted_via_heuristic');
  }
  extractionMethod = 'pdf_heuristic';

} else if (mimeType.startsWith('image/') || magicPNG || magicJPEG) {
  needsOCR = true;
  normalizedText = '';
  sourceFormat = 'image';
  extractionMethod = 'vision_llm';

} else {
  normalizedText = rawBuffer.toString('utf8');
  sourceFormat = 'txt';
  extractionMethod = 'passthrough';
  warnings.push('unknown_format_passthrough');
}

return [{
  json: {
    ...item,
    _normalized_text: normalizedText,
    _needs_ocr: needsOCR,
    _source_format: sourceFormat,
    _extraction_method: extractionMethod,
    _extraction_warnings: warnings,
    _raw_size_bytes: rawBuffer.length,
    _extraction_status: 'ok'
  }
}];

// Extrai texto da resposta do LLM (Anthropic ou OpenAI-compat)
// SEM require(), SEM $env

const ocrResponse = $input.first().json;
const prevItem = $('Precisa OCR?').first().json;

let normalizedText = '';
const warnings = prevItem._extraction_warnings || [];

if (ocrResponse.content && Array.isArray(ocrResponse.content)) {
  // Formato Anthropic
  normalizedText = ocrResponse.content.filter(c => c.type === 'text').map(c => c.text).join('\n');
} else if (ocrResponse.choices && Array.isArray(ocrResponse.choices)) {
  // Formato OpenAI-compat
  normalizedText = ocrResponse.choices[0]?.message?.content || '';
}

if (!normalizedText) warnings.push('ocr_response_empty');
const illegibleCount = (normalizedText.match(/\[ILLEGIBLE\]/g) || []).length;
if (illegibleCount > 0) warnings.push('ocr_illegible_fragments:' + illegibleCount);

// F1-C4 (Arquiteto): sanitização anti prompt-injection no texto OCR'd.
// Remove linhas com tokens canônicos de jailbreak/instrução. Reduz
// superfície de ataque (print de WhatsApp com 'ignore as instruções'
// passaria como conteúdo pras personas). Solução completa = persona
// SEG analisar texto OCR'd (escopo F2/futuro).
const INJECTION_TOKENS = /\b(ignore|ignora|disregard|desconsiderar|forget|esqueça|override|sobrescrever|jailbreak)\s+(previous|all|prior|anteriores?|todas?|qualquer)\b|\bsystem\s*prompt\b|\bprompt\s+injection\b/i;
let sanitizedCount = 0;
if (normalizedText) {
  const lines = normalizedText.split('\n');
  const cleanLines = lines.filter(line => {
    if (INJECTION_TOKENS.test(line)) { sanitizedCount++; return false; }
    return true;
  });
  if (sanitizedCount > 0) {
    normalizedText = cleanLines.join('\n');
    warnings.push('ocr_injection_sanitized:' + sanitizedCount);
  }
}

return [{
  json: {
    ...prevItem,
    _normalized_text: normalizedText,
    _extraction_warnings: warnings,
    _ocr_confidence: illegibleCount > 0 ? Math.max(0.3, 0.85 - illegibleCount * 0.1) : 0.85,
    _extraction_status: normalizedText ? 'ok' : 'failed'
  }
}];

// Monta envelope de saída conforme spec §4.4
// SEM require(), SEM $env — limite 800k chars (F4.1 fix urgente).
// 200k anterior bloqueava peças processuais reais do AJA (>100 pgs).
// 800k cabe em DeepSeek-V3 (64k tok ≈ 250k chars) com risco de truncamento
// em providers de menor context — para chunking estrutural completo,
// ver MVP F4.2+F4.3 (ingestão chunked + accumulator).

const item = $input.first().json;
const normalizedText = item._normalized_text || '';
const MAX_CHARS = 800000;

if (!normalizedText.trim()) {
  return [{ json: { _envelope_status: 'failed', _g1_reason: 'g1_normalization_failed', _g1_detail: 'Texto normalizado vazio', ingestion_id: item.ingestion_id, project_id: item.project_id, callback_url: item.callback_url } }];
}
if (normalizedText.length > MAX_CHARS) {
  return [{ json: { _envelope_status: 'failed', _g1_reason: 'g1_normalization_failed', _g1_detail: `Texto excede ${MAX_CHARS} chars (${normalizedText.length})`, ingestion_id: item.ingestion_id, project_id: item.project_id, callback_url: item.callback_url } }];
}
if (!item._source_format || !item._extraction_method) {
  return [{ json: { _envelope_status: 'failed', _g1_reason: 'g1_normalization_failed', _g1_detail: 'extraction_metadata incompleto', ingestion_id: item.ingestion_id, project_id: item.project_id, callback_url: item.callback_url } }];
}

const envelope = {
  ingestion_id: item.ingestion_id,
  project_id: item.project_id,
  normalized_text: normalizedText,
  extraction_metadata: {
    source_format: item._source_format,
    original_size_bytes: item.document_metadata?.size_bytes || item._raw_size_bytes || 0,
    normalized_char_count: normalizedText.length,
    extraction_method: item._extraction_method,
    extraction_warnings: item._extraction_warnings || [],
    ocr_confidence_estimate: item._ocr_confidence || null,
    filename: item.document_metadata?.filename || '',
    mime_type: item.document_metadata?.mime_type || '',
    page_count: 1,
    tables_detected: 0,
    images_extracted: 0
  },
  provider_chain: item.provider_chain,
  persona_prompts: item.persona_prompts || {},
  seed_shared_context: item.seed_shared_context || {},
  callback_url: item.callback_url,
  received_at: item._received_at || new Date().toISOString()
};

return [{ json: { _envelope_status: 'ok', envelope, ingestion_id: item.ingestion_id, project_id: item.project_id, callback_url: item.callback_url } }];
